/**
 * Generic Spoon transformation to fix SnakeYAML 2.0 breaking change.
 * 
 * This transformation addresses the API change in SnakeYAML 2.0 where 
 * Yaml constructors that previously accepted a Constructor parameter 
 * now require a LoaderOptions parameter as well.
 * 
 * Old API pattern: new Yaml(Constructor constructor)
 * New API pattern: new Yaml(Constructor constructor, LoaderOptions loaderOptions)
 * 
 * The transformation will scan all Java files and update constructor calls 
 * that match this pattern to include a new LoaderOptions() parameter.
 */
public class Main {
    public static void main(String[] args) {
        // This is a placeholder for the actual Spoon transformation
        // The transformation logic will be implemented in the Spoon visitor
    }

    /**
     * Generic visitor that fixes SnakeYAML constructor calls 
     * from SnakeYAML 1.x to 2.0
     */
    public static class SnakeYamlFixVisitor extends CtScanner {
        private final Factory factory;

        public SnakeYamlFixVisitor(Factory factory) {
            this.factory = factory;
        }

        @Override
        public <T> void visitCtConstructorCall(CtConstructorCall<T> ctConstructorCall) {
            // Check if this is a Yaml constructor call with a Constructor parameter
            if (isYamlConstructorCall(ctConstructorCall)) {
                // Check if it's the problematic pattern: new Yaml(Constructor constructor)
                if (isYamlConstructorWithConstructor(ctConstructorCall)) {
                    // Add the LoaderOptions parameter
                    addLoaderOptionsParameter(ctConstructorCall);
                }
            }
            super.visitCtConstructorCall(ctConstructorCall);
        }

        private boolean isYamlConstructorCall(CtConstructorCall<?> ctConstructorCall) {
            if (ctConstructorCall.getType() == null) return false;
            return ctConstructorCall.getType().getQualifiedName().equals("org.yaml.snakeyaml.Yaml");
        }

        private boolean isYamlConstructorWithConstructor(CtConstructorCall<?> ctConstructorCall) {
            // Check if the constructor takes exactly one parameter of type Constructor
            List<CtTypeReference<?>> parameters = ctConstructorCall.getArguments().stream()
                .map(arg -> arg.getType())
                .toList();

            if (parameters.size() == 1) {
                CtTypeReference<?> paramType = parameters.get(0);
                if (paramType != null) {
                    return paramType.getQualifiedName().equals("org.yaml.snakeyaml.constructor.Constructor");
                }
            }
            return false;
        }

        private void addLoaderOptionsParameter(CtConstructorCall<?> ctConstructorCall) {
            // Create new LoaderOptions parameter
            CtConstructorCall<?> loaderOptionsCall = factory.Core().createConstructorCall();
            loaderOptionsCall.setType(factory.Type().createReference("org.yaml.snakeyaml.LoaderOptions"));
            loaderOptionsCall.setArguments(List.of());

            // Add the LoaderOptions parameter to the existing constructor call
            ctConstructorCall.getArguments().add(loaderOptionsCall);
        }
